:root {
  --red: #ff0000;
  --black: #000000;
  --white: #ffffff;
}

/* Base */
* { box-sizing: border-box; }
html { -webkit-text-size-adjust: 100%; }
html, body { height: 100%; }
body {
  margin: 0;
  font-family: system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, "Helvetica Neue", Arial, "Apple Color Emoji", "Segoe UI Emoji";
  color: var(--black);
  background-color: var(--white);
  line-height: 1.6;
}
img, video { max-width: 100%; height: auto; }

.container {
  max-width: 72rem; /* 1152px */
  margin: 0 auto;
  padding: 0 1rem;
}

.section { padding: 2.5rem 0; }
.section-title {
  margin: 0 0 1rem 0;
  font-size: 1.5rem;
  line-height: 1.25;
}

/* Hero */
.hero {
  background: var(--black);
  color: var(--white);
  padding: 3rem 0;
  text-align: center;
}
.hero h1 {
  margin: 0 0 0.5rem 0;
  font-size: 2rem;
  line-height: 1.15;
}
.subtitle {
  margin: 0 0 1.25rem 0;
  color: rgba(255, 255, 255, 0.85);
}

/* Buttons */
.btn {
  display: inline-block;
  padding: 0.75rem 1.25rem;
  border-radius: 0.25rem;
  border: 2px solid var(--red);
  background: var(--red);
  color: var(--white);
  text-decoration: none;
  font-weight: 600;
  cursor: pointer;
  transition: background-color 0.2s ease, color 0.2s ease, transform 0.05s ease;
}
.btn:hover {
  background: rgba(255, 0, 0, 0.85); /* darker red shade */
}
.btn:active { transform: translateY(1px); }
.btn:focus-visible {
  outline: 2px solid var(--red);
  outline-offset: 2px;
}

/* Services */
.services-list {
  list-style: none;
  display: grid;
  grid-template-columns: 1fr;
  gap: 1rem;
  padding: 0;
  margin: 0;
}
.service-card {
  background: var(--white);
  border: 1px solid rgba(0, 0, 0, 0.12);
  border-radius: 0.5rem;
  padding: 1rem;
}
.service-card h3 {
  margin: 0 0 0.5rem 0;
  font-size: 1.125rem;
}
.service-card p {
  margin: 0;
}

/* Contact form */
.contact-form { max-width: 40rem; }
.form-row { margin-bottom: 1rem; }
label {
  display: block;
  margin-bottom: 0.375rem;
}
input[type="text"],
input[type="email"],
textarea {
  width: 100%;
  max-width: 100%;
  padding: 0.625rem 0.75rem;
  border: 1px solid rgba(0, 0, 0, 0.2);
  border-radius: 0.375rem;
  background: var(--white);
  color: var(--black);
}
input::placeholder, textarea::placeholder {
  color: rgba(0, 0, 0, 0.55);
}
input:focus, textarea:focus {
  outline: none;
  border-color: var(--red);
  box-shadow: 0 0 0 3px rgba(255, 0, 0, 0.2);
}

/* Footer */
.site-footer {
  background: var(--black);
  color: var(--white);
  padding: 1rem 0;
  text-align: center;
}

/* Media queries (mobile-first) */
@media (min-width: 40rem) { /* ~640px */
  .hero { padding: 4rem 0; }
  .hero h1 { font-size: 2.5rem; }
  .section { padding: 3rem 0; }
  .services-list { grid-template-columns: repeat(2, 1fr); }
}

@media (min-width: 64rem) { /* ~1024px */
  .hero { padding: 5rem 0; }
  .hero h1 { font-size: 3rem; }
  .services-list { grid-template-columns: repeat(3, 1fr); }
}

document.addEventListener('DOMContentLoaded', function () {
  var form = document.getElementById('contact-form');
  var yearEl = document.getElementById('year');

  if (yearEl) {
    yearEl.textContent = String(new Date().getFullYear());
  }

  if (form) {
    form.addEventListener('submit', function (e) {
      e.preventDefault();
      alert('Thank you! Your message has been noted.');
      if (typeof form.reset === 'function') {
        form.reset();
      }
    });
  }
});

{
  "name": "lab-tech-landing",
  "version": "1.0.0",
  "private": true,
  "description": "Minimal single-page landing site for a lab technician with Jest test.",
  "scripts": {
    "test": "jest"
  },
  "devDependencies": {
    "@types/jest": "^29.5.12",
    "jest": "^29.7.0",
    "jest-environment-jsdom": "^29.7.0",
    "ts-jest": "^29.1.1",
    "typescript": "^5.6.3"
  },
  "jest": {
    "testEnvironment": "jsdom"
  }
}

const fs = require('fs');
const path = require('path');
const { JSDOM } = require('jsdom');

describe('Landing page hero', () => {
  test('has the hero title present', () => {
    const filePath = path.resolve(__dirname, '..', 'index.html');
    const html = fs.readFileSync(filePath, 'utf8');
    const dom = new JSDOM(html);
    const doc = dom.window.document;
    const title = doc.querySelector('#hero-title');
    expect(title).not.toBeNull();
    expect(title.textContent.trim()).toBe('Precise Lab Services');
  });
});
